/* Base variables */
:root {
  --color-bg-primary: #050505;
  --color-bg-elevated: #111111;
  --color-bg-subtle: #1a1a1a;
  --color-surface-light: #f4f6fa;

  --color-primary: #c6ff00;
  --color-primary-soft: rgba(198, 255, 0, 0.12);
  --color-accent-blue: #00aeef;

  --color-text-main: #ffffff;
  --color-text-muted: #b3b3b3;
  --color-text-soft: #8c8c8c;

  --color-border-subtle: #2a2a2a;

  --color-success: #32c85a;
  --color-error: #ff4d4d;
  --color-warning: #ffc857;
  --color-info: #00aeef;

  --font-heading: "Space Grotesk", Helvetica, sans-serif;
  --font-body: "Source Sans 3", Arial, sans-serif;

  --font-size-h1: 34px;
  --font-size-h2: 26px;
  --font-size-h3: 20px;
  --font-size-body: 15px;
  --font-size-small: 12px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  --radius-sm: 2px;
  --radius-md: 4px;
  --radius-lg: 6px;

  --header-height: 72px;
  --max-width: 1200px;
}

/* Global reset-like styles */
*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 16px;
}

body {
  margin: 0;
  min-height: 100vh;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-text-main);
  background: var(--color-bg-primary);
}

ul {
  margin: 0;
  padding: 0;
  list-style: none;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus-visible {
  text-decoration: none;
  color: var(--color-primary);
}

img {
  max-width: 100%;
  height: auto;
}

/* Accessibility */
.skip-link {
  position: absolute;
  left: -999px;
  top: 0;
  padding: var(--space-2) var(--space-3);
  background: var(--color-primary);
  color: #000;
  font-weight: var(--font-weight-semibold);
  z-index: 1000;
}

.skip-link:focus {
  left: var(--space-3);
}

/* Layout helpers */
.header-inner,
.footer-main {
  max-width: var(--max-width);
  margin: 0 auto;
  padding-inline: var(--space-4);
}

/* Header */
.site-header {
  position: sticky;
  top: 0;
  z-index: 100;
  background: #000;
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: var(--header-height);
}

/* Brand */
.brand {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  color: var(--color-text-main);
}

.brand-mark {
  width: 40px;
  height: 40px;
  border-radius: 0;
  background: linear-gradient(135deg, #0b0b0b, #2d2416);
  border: 1px solid #5b4a2b;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  font-size: 18px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: #f9c46b;
}

.brand-text {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.08em;
  font-size: 14px;
  text-transform: uppercase;
}

/* Navigation */
.main-nav {
  flex: 1 1 auto;
  display: flex;
  justify-content: center;
}

.main-nav ul {
  display: flex;
  gap: var(--space-4);
}

.main-nav a {
  position: relative;
  display: inline-flex;
  align-items: center;
  padding-block: 2px;
  font-family: var(--font-heading);
  font-size: 13px;
  letter-spacing: 0.13em;
  text-transform: uppercase;
  font-weight: var(--font-weight-medium);
  color: var(--color-text-main);
}

.main-nav a::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: -6px;
  width: 0;
  height: 2px;
  background: var(--color-primary);
  transition: width 0.18s ease-out;
}

.main-nav a:hover::after,
.main-nav a:focus-visible::after,
.main-nav a[aria-current="page"]::after {
  width: 100%;
}

/* Header actions */
.header-actions {
  display: flex;
  align-items: center;
  gap: var(--space-3);
}

/* Buttons */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 10px 22px;
  border-radius: var(--radius-md);
  border: 1px solid transparent;
  font-family: var(--font-heading);
  font-size: 13px;
  letter-spacing: 0.13em;
  text-transform: uppercase;
  font-weight: var(--font-weight-semibold);
  cursor: pointer;
  transition: background-color 0.16s ease-out, color 0.16s ease-out, border-color 0.16s ease-out;
}

.btn-primary-nav {
  background: var(--color-primary);
  color: #000;
}

.btn-primary-nav:hover,
.btn-primary-nav:focus-visible {
  background: #e4ff4f;
}

/* User menu */
.user-menu {
  position: relative;
  display: flex;
  align-items: center;
}

.user-avatar {
  width: 36px;
  height: 36px;
  border-radius: 999px;
  border: 1px solid var(--color-primary);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  background: #000;
  color: var(--color-primary);
  font-family: var(--font-heading);
  font-size: 16px;
  font-weight: var(--font-weight-semibold);
}

.user-avatar:hover,
.user-avatar:focus-visible {
  background: var(--color-primary-soft);
}

.user-dropdown {
  position: absolute;
  right: 0;
  top: calc(100% + 8px);
  min-width: 160px;
  padding: var(--space-2) 0;
  border-radius: var(--radius-md);
  background: var(--color-bg-elevated);
  border: 1px solid var(--color-border-subtle);
  box-shadow: 0 0 0 1px rgba(0, 0, 0, 0.5);
  opacity: 0;
  visibility: hidden;
  transform: translateY(-4px);
  transition: opacity 0.12s ease-out, transform 0.12s ease-out, visibility 0.12s linear;
  z-index: 10;
}

.user-menu:hover .user-dropdown,
.user-menu:focus-within .user-dropdown {
  opacity: 1;
  visibility: visible;
  transform: translateY(0);
}

.user-dropdown a {
  display: block;
  padding: 8px 14px;
  font-size: 13px;
  color: var(--color-text-main);
}

.user-dropdown a:hover,
.user-dropdown a:focus-visible {
  background: var(--color-bg-subtle);
}

/* Main content */
.site-main {
  min-height: calc(100vh - var(--header-height) - 220px);
  padding: var(--space-5) var(--space-4) var(--space-6);
  max-width: var(--max-width);
  margin: 0 auto;
}

/* Footer */
.site-footer {
  background: #000;
  border-top: 1px solid var(--color-border-subtle);
  margin-top: var(--space-5);
}

.footer-main {
  display: flex;
  flex-wrap: wrap;
  justify-content: space-between;
  gap: var(--space-5);
  padding-top: var(--space-6);
  padding-bottom: var(--space-4);
}

.footer-branding {
  max-width: 320px;
}

.footer-brand {
  margin-bottom: var(--space-3);
}

.footer-description {
  margin: 0;
  color: var(--color-text-muted);
  font-size: 14px;
  line-height: var(--line-height-relaxed);
}

.footer-heading {
  margin: 0 0 var(--space-2);
  font-family: var(--font-heading);
  font-size: 14px;
  font-weight: var(--font-weight-semibold);
  text-transform: none;
}

.site-footer ul li + li {
  margin-top: 6px;
}

.site-footer a {
  color: var(--color-text-main);
  font-size: 14px;
}

.site-footer a:hover,
.site-footer a:focus-visible {
  color: var(--color-primary);
}

/* Footer bottom bar */
.footer-bottom {
  border-top: 1px solid var(--color-border-subtle);
  padding: var(--space-3) var(--space-4);
}

.footer-bottom .copyright {
  max-width: var(--max-width);
  margin: 0 auto;
  padding-inline: var(--space-4);
  color: var(--color-text-soft);
  font-size: 13px;
  text-align: center;
}

/* Utility: alert bar styles matching design */
.alert {
  border-radius: 0;
  background: var(--color-surface-light);
  color: #111;
  padding: 12px 20px;
  font-size: 14px;
  display: flex;
  align-items: center;
  gap: 12px;
  position: relative;
}

.alert::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 3px;
  background: var(--color-accent-blue);
}

.alert-icon {
  width: 16px;
  height: 16px;
  border-radius: 2px;
  border: 1px solid #b3b3b3;
  background: #ffffff;
}

/* Responsive tweaks */
@media (max-width: 1024px) {
  .main-nav ul {
    gap: var(--space-3);
  }

  .brand-text {
    display: none;
  }
}

@media (max-width: 768px) {
  .header-inner {
    flex-wrap: wrap;
    row-gap: var(--space-2);
    height: auto;
    padding-block: var(--space-2);
  }

  .main-nav {
    order: 3;
    width: 100%;
    justify-content: center;
  }

  .main-nav ul {
    flex-wrap: wrap;
    justify-content: center;
    row-gap: var(--space-2);
  }

  .site-main {
    padding-inline: var(--space-3);
  }

  .footer-main {
    padding-inline: var(--space-3);
  }

  .footer-bottom {
    padding-inline: var(--space-3);
  }
}
